import React, { useEffect, useState } from 'react';
import { getSitios, deleteSitio } from './services/culturaService';

function App() {
  const [sitios, setSitios] = useState([]);

  // Se ejecuta apenas se abre la página
  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    const datos = await getSitios();
    setSitios(datos);
  };

  const eliminar = async (id) => {
    if(window.confirm('¿Deseas eliminar este sitio cultural de La Paz?')) {
      await deleteSitio(id);
      cargarDatos(); // Refresca la lista automáticamente
    }
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial' }}>
      <h1 style={{ color: '#d9534f' }}>📍 Cultura La Paz</h1>
      <hr />
      <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap' }}>
        {sitios.map(sitio => (
          <div key={sitio._id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '8px', width: '300px' }}>
            <h3>{sitio.nombre}</h3>
            <p>{sitio.descripcion}</p>
            <p><strong>Ubicación:</strong> {sitio.ubicacion}</p>
            <button 
              onClick={() => eliminar(sitio._id)}
              style={{ background: '#d9534f', color: 'white', border: 'none', padding: '5px 10px', cursor: 'pointer' }}
            >
              Eliminar
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
